fetch dt.system.events
| filter event.provider == "CLASSIC_APPS"
| filter event.type == "app.opened"
| filter isNotNull(dt.app.id)
| lookup [
  data record( AppStatus = decodeBase64ToString($AppsStatus:triplequote) )
  | parse AppStatus, """JSON_ARRAY:AppStatus"""
  | expand AppStatus
  | fieldsAdd describtion = AppStatus[`description`]
  // Suggested replacement app for this classic app
  | fieldsAdd alternative = AppStatus[alternative]
], sourceField:dt.app.id, lookupField:AppStatus[appId]
| fieldsAdd available = isNull(lookup.AppStatus)

| fieldsAdd substring(dt.app.id, from: 0), alias: `app ID`
// The classic app name, linked so it opens directly in Classic
| fieldsAdd `Classic App` = concat("[", coalesce(lookup.describtion, dt.app.id), "](</ui/apps/", dt.app.id, ">)")
// The app that replaces this classic app, as a deep link (em dash when no successor exists yet)
| fieldsAdd alt = lookup.alternative
| fieldsAdd `New App` =
    if(isNull(alt), "—",
       else: concat("[", alt[appName], "](</ui/apps/", alt[appId], ">)"))

// Usage is the page-view count per bin (summed into Views below); UsersTrend is the
// distinct users per bin, so a user who opens the app several times in a bin counts once.
| makeTimeseries Usage = count(default:0), UsersTrend = countDistinct(user.id, default:0),
    by:{`Classic App`, `New App`, dt.app.id, available},
    bins: 24
| fieldsAdd totalUsage = arraySum(Usage)
// Count the distinct users that opened each classic app over the timeframe.
| lookup [
    fetch dt.system.events
    | filter event.provider == "CLASSIC_APPS"
    | filter event.type == "app.opened"
    | filter isNotNull(dt.app.id)
    | summarize uniqueUsers = countDistinct(user.id), by:{dt.app.id}
  ], sourceField: dt.app.id, lookupField: dt.app.id
| fieldsAdd uniqueUsers = lookup.uniqueUsers

| filterOut available
| sort uniqueUsers desc, totalUsage desc
| fieldsAdd Priority = if( available, "🟢",
  else: if (totalUsage < 5, "⚪",
  else: if (totalUsage < 20, "🟡",
  else: "🔴")))

| fields
  timeframe, interval, Priority, `Classic App`, `New App`, `Usage Trend` = UsersTrend, `Views` = totalUsage, `Users` = uniqueUsers

