44.query:
fetch dt.system.events
| filter event.provider == "CLASSIC_APPS"
| filter event.type == "app.opened"
| filter isNotNull(dt.app.id)
| lookup [
  data record( AppStatus = decodeBase64ToString($AppsStatus:triplequote) )
  | parse AppStatus, """JSON_ARRAY:AppStatus"""
  | expand AppStatus
  | fieldsAdd description = AppStatus[`description`]
  // Suggested replacement app for this classic app
  | fieldsAdd alternative = AppStatus[alternative]
], sourceField:dt.app.id, lookupField:AppStatus[appId]
| filter isNotNull(lookup.AppStatus)
| fieldsAdd `Name` = coalesce(lookup.description, dt.app.id)
| fieldsAdd altLink = if(isNotNull(lookup.alternative),
    concat("[", lookup.alternative[appName], "](</ui/apps/", lookup.alternative[appId], ">)"))
| summarize {AppUsage = count(), altLink = takeFirst(altLink)}, by: {user.id, Name}
// Show an approximate, rounded-down view count (e.g. 1234 -> "1k+", 156 -> "100+", 72 -> "50+", 49 -> "10+")
| fieldsAdd ViewsApprox = if(AppUsage >= 1000, concat(toString(toLong(floor(AppUsage / 1000))), "k+"),
    else: if(AppUsage >= 100, concat(toString(toLong(floor(AppUsage / 100)) * 100), "+"),
    else: if(AppUsage >= 50, "50+",
    else: if(AppUsage >= 10, "10+",
    else: toString(AppUsage)))))
// Build a zero-padded sort key from the exact view count and prefix it as
// "<key>||" so the per-user list can be ordered deterministically after it is
// collected (arraySort below); the prefix is stripped before display.
| fieldsAdd sortKey = concat(substring("0000000000", from: stringLength(toString(AppUsage))), toString(AppUsage))
// Pair each classic app and its view count with a link to the app that replaces it (no arrow when no successor exists yet)
| fieldsAdd UsedApp = if(isNotNull(altLink),
    concat(sortKey, "||", Name, " (", ViewsApprox, ") → ", altLink),
    else: concat(sortKey, "||", Name, " (", ViewsApprox, ")"))
| summarize {
    TotalUsage = sum(AppUsage),
    UsedApps = collectArray(UsedApp)
  }, by: {user.id}
// Order each user's apps by their own view count, highest first. arraySort gives
// a guaranteed order that does not depend on the record order collectArray happened
// to see (which DQL does not specify).
| fieldsAdd UsedApps = arraySort(UsedApps, direction: "descending")
| sort TotalUsage desc
// Render one app per line: join the array into a single markdown string,
// separating entries with a blank line so each renders as its own paragraph,
// then drop the "<key>||" sort prefixes and the surrounding brackets and quotes.
// toString gives a JSON array; entries are split on the "comma space" element
// separator, which is safe because app names and link targets never contain it.
| fieldsAdd UsedAppsList = toString(UsedApps)
| fieldsAdd UsedAppsList = replaceString(UsedAppsList, "\", \"", "\n\n")
| fieldsAdd UsedAppsList = replaceString(UsedAppsList, "[\"", "")
| fieldsAdd UsedAppsList = replaceString(UsedAppsList, "\"]", "")
// Strip the sort-key prefix. replacePattern takes a DQL pattern (NOT a regex):
// INT matches the padded digits and '||' is a literal, so this removes "<digits>||".
| fieldsAdd UsedAppsList = replacePattern(UsedAppsList, "INT '||'", "")
// Each user is shown by their account user id, linked to account management where possible.
| fieldsAdd User = if(isNotNull(user.id) and user.id != "UNKNOWN",
    concat("[", user.id, "](https://myaccount.dynatrace.com/account/iam/user-management?user-uuid=", user.id, ")"),
    else: user.id)
| fields User, `Views` = TotalUsage, `New Apps suggestions` = UsedAppsList

