import { monitoredEntitiesClient, settingsObjectsClient } from "@dynatrace-sdk/client-classic-environment-v2";

// Kubernetes monitoring prerequisites that must be reviewed before upgrading to
// Latest Dynatrace. `builtin:cloud.kubernetes.monitoring` is hierarchical — it can be
// configured per cluster as well as at the environment layer. Each monitoring feature
// should be enabled (🟢) for full Kubernetes observability; a disabled feature (🔴) needs
// to be turned on before you upgrade. The environment-level default is always listed; a
// cluster override is listed only when it still leaves a feature disabled.

const SCHEMA_ID = "builtin:cloud.kubernetes.monitoring";

interface SettingsItem {
  scope?: string;
  modified?: string;
  modifiedBy?: string;
  value?: {
    cloudApplicationPipelineEnabled?: boolean;
    openMetricsBuiltinEnabled?: boolean;
    eventProcessingActive?: boolean;
  };
}

function status(enabled?: boolean): string {
  if (enabled === undefined) return STATUS_UNKNOWN;
  return enabled ? "🟢 Enabled" : "🔴 Disabled";
}

function cells(it: SettingsItem): Record<string, string> {
  const v = it.value ?? {};
  return {
    "Namespaces & workloads": status(v.cloudApplicationPipelineEnabled),
    "Workload & node metrics": status(v.openMetricsBuiltinEnabled),
    Events: status(v.eventProcessingActive),
  };
}

export default async function () {
  const items = await fetchAllSettings<SettingsItem>(
    SCHEMA_ID,
    "scope,modified,modifiedBy,value",
  );
  const names = await resolveScopeNames(items.map((it) => it.scope));
  return buildSettingsRows(items, names, cells, settingsLink);
}

function settingsLink(scope: string): string {
  if (!isEnvScope(scope)) {
    return `[Open in settings](/ui/apps/dynatrace.classic.kubernetes/ui/settings/${scope}/${SCHEMA_ID})`;
  }
  return `[Open in settings](/ui/apps/dynatrace.classic.settings/ui/settings/${SCHEMA_ID})`;
}

async function withSettingsRetry<T>(
  fn: () => Promise<T>,
  maxAttempts = 5,
): Promise<T> {
  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    try {
      return await fn();
    } catch (e: unknown) {
      const msg = (e as { message?: string })?.message ?? "";
      const transient = msg.includes("Too many parallel requests") ||
        msg.includes("429");
      if (!transient || attempt === maxAttempts - 1) throw e;
      const delayMs = 400 * Math.pow(2, attempt) + Math.random() * 250;
      await new Promise((r) => setTimeout(r, delayMs));
    }
  }
  throw new Error("unreachable");
}

async function paginateAll<TItem, TRes extends { nextPageKey?: string }>(
  fetchPage: (nextPageKey?: string) => Promise<TRes>,
  extract: (res: TRes) => TItem[] | undefined,
): Promise<TItem[]> {
  let res = await withSettingsRetry(() => fetchPage());
  let items = extract(res) ?? [];
  while (res.nextPageKey) {
    const key = res.nextPageKey;
    res = await withSettingsRetry(() => fetchPage(key));
    items = items.concat(extract(res) ?? []);
  }
  return items;
}

interface SettingsObject<V = unknown> {
  objectId?: string;
  scope?: string;
  modified?: string;
  modifiedBy?: string;
  schemaId?: string;
  value?: V;
}

async function fetchAllSettings<T = SettingsObject>(
  schemaIds: string | string[],
  fields?: string,
): Promise<T[]> {
  const schemaIdsParam = Array.isArray(schemaIds)
    ? schemaIds.join(",")
    : schemaIds;
  const firstArgs = fields
    ? { schemaIds: schemaIdsParam, fields }
    : { schemaIds: schemaIdsParam };
  return paginateAll<T, { items?: unknown[]; nextPageKey?: string }>(
    (nextPageKey) =>
      settingsObjectsClient.getSettingsObjects(
        nextPageKey ? { nextPageKey } : firstArgs,
      ),
    (res) => (res.items ?? []) as T[],
  );
}

const RESOLVABLE = /^(HOST_GROUP|HOST|KUBERNETES_CLUSTER)-/;

async function resolveScopeNames(
  scopes: Array<string | undefined>,
): Promise<Map<string, string>> {
  const map = new Map<string, string>();
  const ids = [
    ...new Set(scopes.filter((s): s is string => !!s && RESOLVABLE.test(s))),
  ];

  for (let i = 0; i < ids.length; i += 50) {
    const batch = ids.slice(i, i + 50);
    const selector = `entityId(${batch.map((id) => `"${id}"`).join(",")})`;
    try {
      let res = await monitoredEntitiesClient.getEntities({
        entitySelector: selector,
        from: "now-2y",
        pageSize: 100,
      });
      while (true) {
        for (const e of res.entities ?? []) {
          if (e.entityId && e.displayName) map.set(e.entityId, e.displayName);
        }
        if (!res.nextPageKey) break;
        res = await monitoredEntitiesClient.getEntities({
          nextPageKey: res.nextPageKey,
        });
      }
    } catch {
    }
  }
  return map;
}

const USER_UUID_RE =
  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

function userManagementLink(value?: string): string {
  if (!value) return value ?? "";
  if (USER_UUID_RE.test(value)) {
    return `[${value}](https://myaccount.dynatrace.com/account/iam/user-management?user-uuid=${value})`;
  }
  return value.replace(/@/g, "\u2060@");
}

const STATUS_UNKNOWN = "⚪ Unknown";
const ACTION_PREFIX = "🔴";

interface ScopedSettingsItem {
  scope?: string;
  modified?: string;
  modifiedBy?: string;
}

function isEnvScope(scope: string): boolean {
  return !scope || scope === "environment";
}

function scopeLabel(scope: string, names: Map<string, string>): string {
  if (isEnvScope(scope)) return "Environment";
  return names.get(scope) ?? scope;
}

function buildSettingsRows<T extends ScopedSettingsItem>(
  items: T[],
  names: Map<string, string>,
  cellsOf: (it: T) => Record<string, string>,
  linkOf: (scope: string) => string,
) {
  const make = (it: T) => {
    const cells = cellsOf(it);
    return {
      scope: scopeLabel(it.scope ?? "", names),
      cells,
      row: {
        Scope: scopeLabel(it.scope ?? "", names),
        ...cells,
        "Last Updated": it.modified ?? "",
        By: userManagementLink(it.modifiedBy) || "⚪ Not found",
        Action: linkOf(it.scope ?? ""),
      },
    };
  };

  const env = items.filter((it) => isEnvScope(it.scope ?? "")).map(make);
  const overrides = items
    .filter((it) => !isEnvScope(it.scope ?? ""))
    .map(make)
    .filter((r) => Object.values(r.cells).some((v) => v.startsWith(ACTION_PREFIX)))
    .sort((a, b) => a.scope.localeCompare(b.scope));

  return [...env, ...overrides].map((r) => r.row);
}

