import { settingsObjectsClient } from "@dynatrace-sdk/client-classic-environment-v2";
import { queryExecutionClient } from "@dynatrace-sdk/client-query";

// Metric-event alerts that still use a classic metric selector, read straight from the
// alerting configuration so the list stays complete, then enriched with the alerts each
// one actually raised in the last 7 days. Status shows how urgent each is: 🔴 enabled and
// raised alerts/problems recently (in the last 7 days, with a rounded volume), 🟡 enabled
// but quiet — or enabled with recent activity unavailable — and ⚪ disabled (nothing to
// migrate). Sorted by recent alert count so the noisiest classic alerts come first. All
// enabled ones must be recreated as DQL-based custom alerts before upgrading — start with
// the 🔴 rows. Alerts already defined with a metric key (DQL) run on the new engine and are not listed.

const SCHEMA_ID = "builtin:anomaly-detection.metric-events";

// Count of alerts/problems each metric event raised in the last 7 days. Davis records the
// originating config on every event as dt.settings.object_id, which matches the settings
// object id exactly — a reliable join key. (dt.davis.events is a curated view and does not
// support sampling, so the 7-day window keeps the scan within tile limits.)
const FIRED_QUERY = `
fetch dt.davis.events, from: now()-7d
| filter event.provider == "METRIC_EVENTS"
| filter dt.settings.schema_id == "${SCHEMA_ID}"
| summarize alerts = count(), by: { object_id = dt.settings.object_id }
| filter alerts > 0`;

interface MetricEventItem {
  objectId?: string;
  author?: string;
  value?: {
    enabled?: boolean;
    summary?: string;
    queryDefinition?: { type?: string };
  };
}

const sleep = (ms: number) => new Promise<void>((resolve) => setTimeout(resolve, ms));

async function firedAlertCounts(): Promise<Map<string, number> | null> {
  const { handle, requestToken } = await queryExecutionClient.queryExecute({
    body: { query: FIRED_QUERY },
  });
  let poll = await queryExecutionClient.queryPoll({
    handle: handle!,
    requestToken: requestToken!,
  });
  while (poll.state !== "SUCCEEDED" && poll.state !== "FAILED") {
    await sleep(2000);
    poll = await queryExecutionClient.queryPoll({
      handle: handle!,
      requestToken: requestToken!,
    });
  }
  if (poll.state === "FAILED") return null;
  const counts = new Map<string, number>();
  for (const rec of poll.result?.records ?? []) {
    const id = rec["object_id"] as string;
    const n = Number(rec["alerts"] ?? 0);
    if (id) counts.set(id, n);
  }
  return counts;
}

// Fuzzy alert volume — we care about magnitude, not the exact number:
// thousands as "Nk", hundreds floored with a "+" (e.g. 639 -> "600+").
function fuzzyCount(n: number): string {
  if (n >= 1000) return `${Math.floor(n / 1000)}k`;
  if (n >= 100) return `${Math.floor(n / 100)}00+`;
  if (n >= 10) return `${Math.floor(n / 10)}0+`;
  return `${n}`;
}

function settingsLink(name: string): string {
  const url =
    `/ui/apps/dynatrace.classic.settings/ui/settings/${SCHEMA_ID}` +
    `?gtf=-2h&gf=all&filter=summary%3A${encodeURIComponent(name)}`;
  return `[Open settings](${url})`;
}

export default async function () {
  const [items, fired] = await Promise.all([
    fetchAllSettings<MetricEventItem>(SCHEMA_ID, "objectId,author,value"),
    firedAlertCounts(),
  ]);
  return items
    .filter((it) => it.value?.queryDefinition?.type === "METRIC_SELECTOR")
    .map((it) => {
      const name = it.value?.summary ?? it.objectId ?? "(no name)";
      const enabled = it.value?.enabled === true;
      const count = (it.objectId && fired?.get(it.objectId)) || 0;
      const cat = !enabled ? 3 : fired === null ? 1 : count > 0 ? 0 : 2;
      return { name, count, cat, author: it.author };
    })
    .sort((a, b) => {
      if (a.cat !== b.cat) return a.cat - b.cat;
      if (a.cat === 0 && a.count !== b.count) return b.count - a.count;
      return a.name.localeCompare(b.name);
    })
    .map(({ name, count, cat, author }) => {
      const status = cat === 3
        ? "⚪ Disabled"
        : cat === 1
          ? "🟡 Enabled · recent activity unavailable"
          : cat === 0
            ? `🔴 Enabled · ${fuzzyCount(count)} alert${count === 1 ? "" : "s"} recently`
            : "🟡 Enabled, no recent alerts";
      return {
        "Alert name": name,
        Status: status,
        Author: userManagementLink(author) || "⚪ Not found",
        Action: settingsLink(name),
      };
    });
}

async function withSettingsRetry<T>(
  fn: () => Promise<T>,
  maxAttempts = 5,
): Promise<T> {
  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    try {
      return await fn();
    } catch (e: unknown) {
      const msg = (e as { message?: string })?.message ?? "";
      const transient = msg.includes("Too many parallel requests") ||
        msg.includes("429");
      if (!transient || attempt === maxAttempts - 1) throw e;
      const delayMs = 400 * Math.pow(2, attempt) + Math.random() * 250;
      await new Promise((r) => setTimeout(r, delayMs));
    }
  }
  throw new Error("unreachable");
}

async function paginateAll<TItem, TRes extends { nextPageKey?: string }>(
  fetchPage: (nextPageKey?: string) => Promise<TRes>,
  extract: (res: TRes) => TItem[] | undefined,
