import { monitoredEntitiesClient, settingsObjectsClient } from "@dynatrace-sdk/client-classic-environment-v2";

// Classic infrastructure disk anomaly detection settings that must be reviewed before
// upgrading to Latest Dynatrace. `builtin:anomaly-detection.infrastructure-disks` is
// hierarchical — detections can be configured per host or host group as well as at the
// environment layer. Classic disk anomaly detection is being replaced by the new disk
// alerting: a detection still enabled (🔴) must be recreated before you upgrade, a
// disabled one (🟢) has nothing to migrate. The environment-level default is always
// listed; a host / host-group override is listed only when it still leaves a detection
// enabled.

const SCHEMA_ID = "builtin:anomaly-detection.infrastructure-disks";

interface Detection {
  enabled?: boolean;
}
interface SettingsItem {
  scope?: string;
  modified?: string;
  modifiedBy?: string;
  value?: {
    disk?: {
      diskLowSpaceDetection?: Detection;
      diskSlowWritesAndReadsDetection?: Detection;
      diskLowInodesDetection?: Detection;
    };
  };
}

function status(d?: Detection): string {
  if (d?.enabled === undefined) return STATUS_UNKNOWN;
  return d.enabled ? "🔴 Enabled" : "🟢 Disabled";
}

function cells(it: SettingsItem): Record<string, string> {
  const disk = it.value?.disk ?? {};
  return {
    "Low disk space": status(disk.diskLowSpaceDetection),
    "Slow disks": status(disk.diskSlowWritesAndReadsDetection),
    "Low inodes": status(disk.diskLowInodesDetection),
  };
}

export default async function () {
  const items = await fetchAllSettings<SettingsItem>(
    SCHEMA_ID,
    "scope,modified,modifiedBy,value",
  );
  const names = await resolveScopeNames(items.map((it) => it.scope));
  return buildSettingsRows(items, names, cells, settingsLink);
}

function settingsLink(scope: string): string {
  if (!isEnvScope(scope)) {
    return `[Open in settings](/ui/apps/dynatrace.classic.hosts/ui/settings/${scope}/${SCHEMA_ID})`;
