// Global Request Naming Rules that use upgrade-incompatible conditions:
// management zones, non-`primary_tags.` PG tags, or any service tag.
const BASE_URL = "/platform-reserved/classic-config/v1/service/requestNaming";

interface TagInfo {
  key?: string;
  value?: string;
}

interface ComparisonInfo {
  type?: string;
  value?: TagInfo;
  values?: TagInfo[];
}

interface NamingCondition {
  attribute?: string;
  comparisonInfo?: ComparisonInfo;
}

interface RequestNamingRule {
  id?: string;
  // request-naming rules don't carry a top-level `name` field; the rule is
  // identified by the request-name template it generates.
  namingPattern?: string;
  description?: string;
  enabled?: boolean;
  managementZones?: unknown[];
  conditions?: NamingCondition[];
}

interface ListStub {
  id: string;
}

interface ListResponse {
  values?: ListStub[];
}

export default async function () {
  const items = await fetchRequestNamingRules();
  const flagged = items
    .filter((item) => item.enabled !== false)
    .filter((item) => isFlaggable(item));

  return flagged.map(toDisplayRow);
}

function toDisplayRow(item: RequestNamingRule) {
  const reasons: string[] = [];
  if ((item.managementZones ?? []).length > 0) reasons.push("Management zone");
  const conditions = item.conditions ?? [];
  const hasNonPrimaryPG = conditions.some(
    (c) =>
      c.attribute === "PROCESS_GROUP_TAG" &&
      c.comparisonInfo?.type === "TAG" &&
      hasNonPrimaryTag(c.comparisonInfo),
  );
  if (hasNonPrimaryPG) reasons.push("Non-primary PG tag");
  if (conditions.some((c) => c.attribute === "SERVICE_TAG")) {
    reasons.push("Service tag");
  }

  return {
    "Naming pattern": item.namingPattern ?? item.description ?? "(no pattern)",
    Reason: reasons.join(", "),
    Conditions: conditions.length,
    ID: item.id ?? "",
  };
}

function isFlaggable(item: RequestNamingRule): boolean {
  if (item.managementZones && item.managementZones.length > 0) return true;

  const conditions = item.conditions ?? [];
  return conditions.some((cond) => {
    const { attribute, comparisonInfo } = cond;

    if (attribute === "PROCESS_GROUP_TAG" && comparisonInfo?.type === "TAG") {
      return hasNonPrimaryTag(comparisonInfo);
    }

    if (attribute === "SERVICE_TAG") return true;

    return false;
  });
}

function hasNonPrimaryTag(comparisonInfo: ComparisonInfo): boolean {
  const single = comparisonInfo.value;
  if (single && !isPrimaryTag(single)) return true;

  const multi = comparisonInfo.values ?? [];
  return multi.some((v) => !isPrimaryTag(v));
}

function isPrimaryTag(tagInfo: TagInfo): boolean {
  return tagInfo.key?.startsWith("primary_tags:") ?? false;
}

