import { extensions_2_0Client } from "@dynatrace-sdk/client-classic-environment-v2";

// Cloud connection telemetry-enrichment state, as pie slices mirroring the table's
// status taxonomy: Migrated (on the central enrichment config) · Action required
// (enabled, still has connection-embedded enrichment rules) · Review (enabled, no
// embedded rules) · Disabled (connection turned off).

export default async function () {
  const connections = await fetchCloudConnections();
  const counts: Record<string, number> = {
    Migrated: 0,
    "Action required": 0,
    Review: 0,
    Disabled: 0,
  };
  for (const c of connections) counts[connectionState(c)]++;
  return [
    { category: "Migrated", connections: counts["Migrated"] },
    { category: "Action required", connections: counts["Action required"] },
    { category: "Review", connections: counts["Review"] },
    { category: "Disabled", connections: counts["Disabled"] },
  ];
}

async function withSettingsRetry<T>(
  fn: () => Promise<T>,
  maxAttempts = 5,
): Promise<T> {
  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    try {
      return await fn();
    } catch (e: unknown) {
      const msg = (e as { message?: string })?.message ?? "";
      const transient = msg.includes("Too many parallel requests") ||
        msg.includes("429");
      if (!transient || attempt === maxAttempts - 1) throw e;
      const delayMs = 400 * Math.pow(2, attempt) + Math.random() * 250;
      await new Promise((r) => setTimeout(r, delayMs));
    }
  }
  throw new Error("unreachable");
}

interface CloudConnection {
  provider: string;
  name: string;
  enabled: boolean;
  enrichmentRules: number;
  migrated: boolean;
  objectId: string;
}

interface CloudExtension {
  name: string;
  provider: string;
  block: string;
}

const CLOUD_EXTENSIONS: CloudExtension[] = [
  { name: "com.dynatrace.extension.da-aws", provider: "AWS", block: "aws" },
  { name: "com.dynatrace.extension.da-azure", provider: "Azure", block: "azure" },
  { name: "com.dynatrace.extension.da-gcp", provider: "GCP", block: "googleCloud" },
];

async function fetchCloudConnections(): Promise<CloudConnection[]> {
  const out: CloudConnection[] = [];
  for (const ext of CLOUD_EXTENSIONS) {
    let nextPageKey: string | undefined;
    try {
      do {
        const page = (await withSettingsRetry(() =>
          extensions_2_0Client.extensionMonitoringConfigurations({
            extensionName: ext.name,
            pageSize: 100,
            ...(nextPageKey ? { nextPageKey } : {}),
          }),
        )) as {
          items?: Array<{ objectId?: string; value?: Record<string, any> }>;
          nextPageKey?: string;
        };
        for (const item of page?.items ?? []) {
          const value = item?.value ?? {};
          const block = (value[ext.block] as Record<string, unknown>) ?? {};
          const tag = Array.isArray(block.tagEnrichment) ? block.tagEnrichment.length : 0;
          const label = Array.isArray(block.labelEnrichment) ? block.labelEnrichment.length : 0;
          const migrated =
            value.useIngestEnrichmentConfig === true ||
            (block as Record<string, unknown>).useIngestEnrichmentConfig === true;
          out.push({
            provider: ext.provider,
            name: (value.description as string) || item.objectId || "(unnamed connection)",
            enabled: value.enabled === true,
            enrichmentRules: tag + label,
            migrated,
            objectId: item.objectId || "",
          });
        }
        nextPageKey = page?.nextPageKey;
      } while (nextPageKey);
    } catch (e: unknown) {
      const err = e as { status?: number; response?: { status?: number }; message?: string };
      const status = err?.status ?? err?.response?.status;
      const notInstalled = status === 404 || /\b404\b|not found/i.test(err?.message ?? "");
      if (notInstalled) continue;
      throw e;
    }
  }
  return out;
}

function connectionState(c: CloudConnection): string {
  if (c.migrated) return "Migrated";
  if (!c.enabled) return "Disabled";
  return c.enrichmentRules > 0 ? "Action required" : "Review";
}

