import { settingsObjectsClient } from "@dynatrace-sdk/client-classic-environment-v2";
import { queryExecutionClient } from "@dynatrace-sdk/client-query";

// Classic infrastructure monitoring rules that must be reviewed before upgrading to Latest Dynatrace.
// Combines OS / Windows-service monitoring (`builtin:os.services.monitoring`) and
// network-connection monitoring (`builtin:network-connection-monitoring`). These are
// hierarchical settings — rules can be defined at the environment, host-group or host
// layer — so every configured object across all layers is listed. The Type column shows
// the classic feature and the Scope column the layer (environment / host group / host)
// the rule applies to.

const TYPE_BY_SCHEMA: Record<string, string> = {
  "builtin:os.services.monitoring": "Windows services",
  "builtin:network-connection-monitoring": "Network connections",
};

interface SettingsItem {
  objectId?: string;
  scope?: string;
  modified?: string;
  schemaId?: string;
  summary?: string;
  value?: {
    enabled?: boolean;
    displayName?: string;
    name?: string;
    description?: string;
    serviceName?: string;
  };
}

export default async function () {
  const items = await fetchAllSettings<SettingsItem>(
    Object.keys(TYPE_BY_SCHEMA).join(","),
    "objectId,scope,modified,schemaId,summary,value",
  );
  const scopeNames = await resolveScopeNames(items);
  return items.map((it) => toRow(it, scopeNames));
}

function toRow(it: SettingsItem, scopeNames: Map<string, string>) {
  const name = it.summary || it.value?.displayName || it.value?.name ||
    it.value?.description || it.value?.serviceName || "(unnamed rule)";
  return {
    Type: TYPE_BY_SCHEMA[it.schemaId ?? ""] ?? (it.schemaId ?? ""),
    Name: name,
    Scope: scopeLabel(it.scope ?? "", scopeNames),
    "Last changed": it.modified ?? "",
    Action: settingsLink(it.scope ?? "", it.schemaId ?? ""),
  };
}

function settingsLink(scope: string, schemaId: string): string {
  if (!schemaId) return "";
  if (scope && scope !== "environment") {
    return `[Open in settings](/ui/apps/dynatrace.classic.hosts/ui/settings/${scope}/${schemaId})`;
  }
  return `[Open in settings](/ui/apps/dynatrace.classic.settings/ui/settings/${schemaId})`;
}

function scopeLabel(scope: string, names: Map<string, string>): string {
  if (!scope || scope === "environment") return "Environment";
  return names.get(scope) ?? scope;
}

async function resolveScopeNames(
  items: SettingsItem[],
): Promise<Map<string, string>> {
  const map = new Map<string, string>();
  const scopes = new Set(
    items.map((it) => it.scope).filter((s): s is string => !!s),
  );
  const hosts = [...scopes].filter((s) => s.startsWith("HOST-"));
  const groups = [...scopes].filter((s) => s.startsWith("HOST_GROUP-"));
  if (hosts.length) {
    await resolveEntities(
      `fetch dt.entity.host | filter in(id, ${idList(hosts)}) | fields id, entity.name`,
      map,
    );
  }
  if (groups.length) {
    await resolveEntities(
      `fetch dt.entity.host_group | filter in(id, ${idList(groups)}) | fields id, entity.name`,
      map,
    );
  }
  return map;
}

function idList(ids: string[]): string {
  return ids.map((id) => `"${id}"`).join(", ");
}

async function resolveEntities(
  query: string,
  map: Map<string, string>,
): Promise<void> {
  const { handle, requestToken } = await queryExecutionClient.queryExecute({
    body: { query },
  });
  let poll = await queryExecutionClient.queryPoll({
    handle: handle!,
    requestToken: requestToken!,
  });
  while (poll.state !== "SUCCEEDED" && poll.state !== "FAILED") {
    poll = await queryExecutionClient.queryPoll({
      handle: handle!,
      requestToken: requestToken!,
    });
  }
  for (const rec of poll.result?.records ?? []) {
    const id = rec["id"] as string;
    const name = rec["entity.name"] as string;
    if (id && name) map.set(id, name);
  }
}

async function withSettingsRetry<T>(
  fn: () => Promise<T>,
  maxAttempts = 5,
): Promise<T> {
  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    try {
      return await fn();
    } catch (e: unknown) {
      const msg = (e as { message?: string })?.message ?? "";
      const transient = msg.includes("Too many parallel requests") ||
        msg.includes("429");
      if (!transient || attempt === maxAttempts - 1) throw e;
      const delayMs = 400 * Math.pow(2, attempt) + Math.random() * 250;
      await new Promise((r) => setTimeout(r, delayMs));
    }
  }
  throw new Error("unreachable");
}

async function paginateAll<TItem, TRes extends { nextPageKey?: string }>(
  fetchPage: (nextPageKey?: string) => Promise<TRes>,
  extract: (res: TRes) => TItem[] | undefined,
): Promise<TItem[]> {
  let res = await withSettingsRetry(() => fetchPage());
  let items = extract(res) ?? [];
  while (res.nextPageKey) {
    const key = res.nextPageKey;
    res = await withSettingsRetry(() => fetchPage(key));
    items = items.concat(extract(res) ?? []);
  }
  return items;
}

interface SettingsObject<V = unknown> {
  objectId?: string;
  scope?: string;
  modified?: string;
  modifiedBy?: string;
  schemaId?: string;
  value?: V;
}

async function fetchAllSettings<T = SettingsObject>(
  schemaIds: string | string[],
  fields?: string,
): Promise<T[]> {
  const schemaIdsParam = Array.isArray(schemaIds)
    ? schemaIds.join(",")
    : schemaIds;
  const firstArgs = fields
    ? { schemaIds: schemaIdsParam, fields }
    : { schemaIds: schemaIdsParam };
  return paginateAll<T, { items?: unknown[]; nextPageKey?: string }>(
    (nextPageKey) =>
      settingsObjectsClient.getSettingsObjects(
        nextPageKey ? { nextPageKey } : firstArgs,
      ),
    (res) => (res.items ?? []) as T[],
  );
}

