import { settingsObjectsClient } from "@dynatrace-sdk/client-classic-environment-v2";
import { queryExecutionClient } from "@dynatrace-sdk/client-query";

// K8s clusters whose metadata-enrichment rules are still on the legacy
// `builtin:kubernetes.generic.metadata.enrichment` schema and have not yet
// opted in to the new central `builtin:ingest.enrichment.config` schema.
// One row per scope (cluster or environment). Toggling the per-object
// `useIngestEnrichmentConfig` flag forward-migrates the rules into the
// new central schema; rows listed here still need that switch.

interface EnrichmentValue {
  useIngestEnrichmentConfig?: boolean;
  rules?: unknown[];
}
interface SettingsItem {
  objectId?: string;
  scope?: string;
  modified?: string;
  value?: EnrichmentValue;
}

const SCHEMA_ID = 'builtin:kubernetes.generic.metadata.enrichment';

export default async function () {
  const all = await fetchAllSettings<SettingsItem>(SCHEMA_ID, 'objectId,scope,modified,value');
  const items = all.filter((it) => it.value?.useIngestEnrichmentConfig !== true);
  const clusterNames = await fetchClusterNames(items);
  return items.map((it) => toRow(it, clusterNames)).sort((a, b) => b['Legacy rules'] - a['Legacy rules']);
}

async function fetchClusterNames(items: SettingsItem[]): Promise<Map<string, string>> {
  const map = new Map<string, string>();
  const ids = [
    ...new Set(items.map((it) => it.scope).filter((s): s is string => !!s && s.startsWith('KUBERNETES_CLUSTER-'))),
  ];
  if (ids.length === 0) return map;

  const idList = ids.map((id) => `"${id}"`).join(', ');
  const { handle, requestToken } = await queryExecutionClient.queryExecute({
    body: { query: `fetch dt.entity.kubernetes_cluster | filter in(id, ${idList}) | fields id, entity.name` },
  });
  let poll = await queryExecutionClient.queryPoll({ handle: handle!, requestToken: requestToken! });
  while (poll.state !== 'SUCCEEDED' && poll.state !== 'FAILED') {
    poll = await queryExecutionClient.queryPoll({ handle: handle!, requestToken: requestToken! });
  }
  for (const record of poll.result?.records ?? []) {
    const id = record['id'] as string;
    const name = record['entity.name'] as string;
    if (id && name) map.set(id, name);
  }
  return map;
}

function toRow(it: SettingsItem, clusterNames: Map<string, string>) {
  const scope = it.scope || '(unscoped)';
  const cluster = scope.startsWith('KUBERNETES_CLUSTER-') ? (clusterNames.get(scope) ?? scope) : scope;
  return {
    'Cluster': cluster,
    'Legacy rules': it.value?.rules?.length ?? 0,
    'Last changed': it.modified ?? '',
    Action: actionLink(scope),
  };
}

function actionLink(scope: string): string {
  if (scope.startsWith('KUBERNETES_CLUSTER-')) {
    return `[Open in settings](/ui/apps/dynatrace.classic.kubernetes/ui/settings/${scope}/${SCHEMA_ID})`;
  }
  return `[Open in settings](/ui/apps/dynatrace.classic.settings/ui/settings/${SCHEMA_ID})`;
}

async function withSettingsRetry<T>(
  fn: () => Promise<T>,
  maxAttempts = 5,
): Promise<T> {
  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    try {
      return await fn();
    } catch (e: unknown) {
      const msg = (e as { message?: string })?.message ?? "";
      const transient = msg.includes("Too many parallel requests") ||
        msg.includes("429");
      if (!transient || attempt === maxAttempts - 1) throw e;
      const delayMs = 400 * Math.pow(2, attempt) + Math.random() * 250;
      await new Promise((r) => setTimeout(r, delayMs));
    }
  }
  throw new Error("unreachable");
}

async function paginateAll<TItem, TRes extends { nextPageKey?: string }>(
  fetchPage: (nextPageKey?: string) => Promise<TRes>,
  extract: (res: TRes) => TItem[] | undefined,
): Promise<TItem[]> {
  let res = await withSettingsRetry(() => fetchPage());
  let items = extract(res) ?? [];
  while (res.nextPageKey) {
    const key = res.nextPageKey;
    res = await withSettingsRetry(() => fetchPage(key));
    items = items.concat(extract(res) ?? []);
  }
  return items;
}

interface SettingsObject<V = unknown> {
  objectId?: string;
  scope?: string;
  modified?: string;
  modifiedBy?: string;
  schemaId?: string;
  value?: V;
}

async function fetchAllSettings<T = SettingsObject>(
  schemaIds: string | string[],
  fields?: string,
): Promise<T[]> {
  const schemaIdsParam = Array.isArray(schemaIds)
    ? schemaIds.join(",")
    : schemaIds;
  const firstArgs = fields
    ? { schemaIds: schemaIdsParam, fields }
    : { schemaIds: schemaIdsParam };
  return paginateAll<T, { items?: unknown[]; nextPageKey?: string }>(
    (nextPageKey) =>
