import { settingsObjectsClient } from "@dynatrace-sdk/client-classic-environment-v2";

// Classic issue-tracking integrations of the Releases app. Each moves to the new model
// on upgrade; enabled integrations are actively in use, so recreate those first.

const SCHEMA_ID = "builtin:issue-tracking.integration";
const SETTINGS_BASE = `/ui/apps/dynatrace.classic.settings/ui/settings/${SCHEMA_ID}`;

function objectIdToUuid(objectId?: string): string | null {
  if (!objectId) return null;
  try {
    const decoded = atob(objectId);
    const matches = decoded.match(
      /[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}/g,
    );
    return matches && matches.length ? matches[matches.length - 1] : null;
  } catch {
    return null;
  }
}

function settingsLink(objectId?: string): string {
  const uuid = objectIdToUuid(objectId);
  return uuid ? `[Open settings](${SETTINGS_BASE}?id=${uuid})` : "";
}

export default async function () {
  const integrations = await fetchIssueTracking();
  return integrations
    .sort(
      (a, b) =>
        Number(b.enabled) - Number(a.enabled) || a.label.localeCompare(b.label),
    )
    .map((i) => ({
      Integration: i.label,
      "Issue tracker": i.tracker,
      Status: issueTrackingStatus(i.enabled),
      Action: settingsLink(i.objectId),
    }));
}

async function withSettingsRetry<T>(
  fn: () => Promise<T>,
  maxAttempts = 5,
): Promise<T> {
  for (let attempt = 0; attempt < maxAttempts; attempt++) {
    try {
      return await fn();
    } catch (e: unknown) {
      const msg = (e as { message?: string })?.message ?? "";
      const transient = msg.includes("Too many parallel requests") ||
        msg.includes("429");
      if (!transient || attempt === maxAttempts - 1) throw e;
      const delayMs = 400 * Math.pow(2, attempt) + Math.random() * 250;
      await new Promise((r) => setTimeout(r, delayMs));
    }
  }
  throw new Error("unreachable");
}

async function paginateAll<TItem, TRes extends { nextPageKey?: string }>(
  fetchPage: (nextPageKey?: string) => Promise<TRes>,
  extract: (res: TRes) => TItem[] | undefined,
): Promise<TItem[]> {
  let res = await withSettingsRetry(() => fetchPage());
  let items = extract(res) ?? [];
  while (res.nextPageKey) {
    const key = res.nextPageKey;
    res = await withSettingsRetry(() => fetchPage(key));
    items = items.concat(extract(res) ?? []);
  }
  return items;
}

interface SettingsObject<V = unknown> {
  objectId?: string;
  scope?: string;
  modified?: string;
  modifiedBy?: string;
  schemaId?: string;
  value?: V;
}

async function fetchAllSettings<T = SettingsObject>(
