    ? { schemaIds: schemaIdsParam, fields }
    : { schemaIds: schemaIdsParam };
  return paginateAll<T, { items?: unknown[]; nextPageKey?: string }>(
    (nextPageKey) =>
      settingsObjectsClient.getSettingsObjects(
        nextPageKey ? { nextPageKey } : firstArgs,
