import { settingsObjectsClient } from "@dynatrace-sdk/client-classic-environment-v2";

// Web/Mobile frontends actively using RUM but not yet on Grail — the real migration work.
// Excludes RUM-disabled frontends (those are surfaced in the table as gray and likely don't
// need migration) and Custom apps (counted separately). A frontend counts here only when
// RUM is enabled and not yet on Grail.

const ENV = 'environment';
