import { settingsObjectsClient } from "@dynatrace-sdk/client-classic-environment-v2";

// Frontend RUM experience state, as pie slices that mirror the table's status taxonomy:
// On Grail (done) · Not on Grail (enabled, needs migration) · Disabled (surfaced, likely
// no migration) · Custom (unsupported on Grail). Web/Mobile are partitioned by enablement;
// Custom is its own slice.

const ENV = 'environment';
const WM_NAME_SCHEMAS = ['builtin:rum.web.name', 'builtin:rum.mobile.name'];
const ENABLEMENT_SCHEMAS = ['builtin:rum.web.enablement', 'builtin:rum.mobile.enablement'];

export default async function () {
  const [wmNames, enablements, customNames] = await Promise.all([
    fetchAllSettings(WM_NAME_SCHEMAS, 'scope,value'),
    fetchAllSettings(ENABLEMENT_SCHEMAS, 'scope,value'),
    fetchAllSettings(['builtin:rum.custom.name'], 'scope,value'),
  ]);
  const rumByScope = new Map(
    enablements.filter(o => o.scope !== ENV).map(o => [o.scope, o.value && o.value.rum])
  );
