import { settingsObjectsClient } from "@dynatrace-sdk/client-classic-environment-v2";

// Frontends not yet on the new RUM (Grail) experience — the migration to-do list.
// On-Grail frontends are summarised by the pie and counts and are intentionally omitted
// here. Custom application frontends are listed because they aren't supported on Grail yet.
// Sorted by severity (most urgent first), then name. The last column links Web and Mobile
// frontends directly to their RUM enablement settings; Custom frontends link to the
// Experience Vitals overview (no enablement settings are available for Custom apps).

const ENV = 'environment';
const EV_BASE = '/ui/apps/dynatrace.experience.vitals/frontends/';
const SCHEMAS = {
  Web:    { name: 'builtin:rum.web.name',    enablement: 'builtin:rum.web.enablement' },
  Mobile: { name: 'builtin:rum.mobile.name', enablement: 'builtin:rum.mobile.enablement' },
  Custom: { name: 'builtin:rum.custom.name', enablement: null },
};

function classify(type, rum) {
  if (type === 'Custom') return { rank: 2, status: '⚪ No Grail path yet' };
  if (rum && rum.enabledOnGrail === true) return null;
  if (rum && rum.enabled === true) return { rank: 0, status: '🔴 Not on Grail' };
  return { rank: 1, status: '⚪ RUM disabled' };
}

function settingsLink(scope, schema) {
  if (!schema) return `[Open Experience Vitals](${EV_BASE}${scope}/overview)`;
  return `[Enable RUM](${EV_BASE}${scope}/settings/${encodeURIComponent(schema)})`;
}

export default async function () {
  const types = Object.keys(SCHEMAS);
  const perType = await Promise.all(types.map(async (type) => {
    const [names, enablements] = await Promise.all([
      fetchAllSettings(SCHEMAS[type].name, 'scope,value'),
      SCHEMAS[type].enablement ? fetchAllSettings(SCHEMAS[type].enablement, 'scope,value') : Promise.resolve([]),
    ]);
    const rumByScope = new Map(
      enablements.filter(o => o.scope !== ENV).map(o => [o.scope, o.value && o.value.rum])
    );
    return { type, names: names.filter(o => o.scope !== ENV), rumByScope };
  }));

  const rows = perType.flatMap(({ type, names, rumByScope }) =>
    names
      .map(o => {
        const c = classify(type, rumByScope.get(o.scope));
        if (c === null) return null;
        const name = (o.value && o.value.applicationName) || o.scope;
        return {
          _rank: c.rank,
          Frontend: String(name),
          Type: type,
          Status: c.status,
          Action: settingsLink(o.scope, SCHEMAS[type].enablement),
          id: o.scope,
        };
      })
      .filter(r => r !== null)
  );

  return rows
    .sort((a, b) => a._rank - b._rank || a.Frontend.localeCompare(b.Frontend))
    .map(({ _rank, ...row }) => row);
