import { activeGatesClient } from "@dynatrace-sdk/client-classic-environment-v2";

// ActiveGate auth-token readiness as pie slices: Ready (version 1.225+ with a valid token)
// versus the two reasons an ActiveGate is not ready — below version 1.225 (or unknown
// version), or token needs attention (absent, expiring, invalid, or unsupported). Each
// ActiveGate falls into exactly one slice (version is checked first).

export default async function () {
  const gates = await fetchAllActiveGates();
  let ready = 0;
  let oldVersion = 0;
  let tokenBad = 0;
  for (const g of gates) {
    const minor = agMinorVersion(g.version);
    if (Number.isNaN(minor) || minor < MIN_AUTH_TOKEN_MINOR) oldVersion++;
    else if (TOKEN_NOT_READY.includes(g.tokenState ?? '')) tokenBad++;
    else ready++;
