interface ActiveGate {
  id?: string;
  type?: string; // ENVIRONMENT | CLUSTER
  hostname?: string;
  version?: string; // e.g. "1.315.20.20250101"
  networkZone?: string;
  tokenState?: string; // OK | ABSENT | EXPIRING | INVALID | UNKNOWN | UNSUPPORTED
}

const TOKEN_NOT_READY = ["ABSENT", "EXPIRING", "INVALID", "UNKNOWN", "UNSUPPORTED"];

const MIN_AUTH_TOKEN_MINOR = 225;

function agMinorVersion(version?: string): number {
  if (!version) return NaN;
  const parts = version.split(".");
  return parts.length >= 2 ? Number(parts[1]) : NaN;
}

function paginate(args: Record<string, unknown>): Promise<ActiveGate[]> {
  return paginateAll<ActiveGate, { activeGates?: unknown[]; nextPageKey?: string }>(
