async function fetchAllActiveGates(): Promise<ActiveGate[]> {
  const all = await paginate({});
  const stateById: Record<string, string> = {};
  for (const state of TOKEN_NOT_READY) {
    const flagged = await paginate({ tokenState: state });
    for (const g of flagged) if (g.id) stateById[g.id] = state;
