const SCHEMA_ID = "builtin:cloud.kubernetes.monitoring";
const ENV = "environment";

interface Item {
  scope?: string;
  value?: {
    cloudApplicationPipelineEnabled?: boolean;
    openMetricsBuiltinEnabled?: boolean;
    eventProcessingActive?: boolean;
  };
}

export default async function () {
  const items = await fetchAllSettings<Item>(SCHEMA_ID, "scope,value");
  const env = items.find((i) => i.scope === ENV)?.value ?? {};
  const clusters = items.filter((i) => i.scope !== ENV);

  let action = 0;
  for (const it of clusters) {
    const v = it.value ?? {};
    const pipeline = v.cloudApplicationPipelineEnabled ?? env.cloudApplicationPipelineEnabled;
    const openMetrics = v.openMetricsBuiltinEnabled ?? env.openMetricsBuiltinEnabled;
