// Share of logs and business-event records by the pipeline that processed them — a snapshot of
// the classic-vs-OpenPipeline split shown over time in the chart. "Classic Pipeline" is the legacy
// default route being removed; "OpenPipeline" is any configured OpenPipeline route. Records still
// on the Classic Pipeline are the volume to migrate before classic processing is switched off.
timeseries records = sum(dt.sfm.openpipeline.routing.records, default: 0),
  by: { route_name },
  filter: { in(configuration, {"logs", "bizevents"}) },
  bins: 1
| fieldsAdd Pipeline = if(matchesValue(route_name, "default"), "Classic Pipeline", else: "OpenPipeline"),
    Records = arraySum(records)
| summarize Records = sum(Records), by: { Pipeline }
// Seed both categories at zero so the pie always shows both slices, even when one pipeline
// currently has no records (for example a fully-migrated environment).
| append [
    data record(Pipeline = "Classic Pipeline", Records = 0.0),
      record(Pipeline = "OpenPipeline", Records = 0.0)
  ]
| summarize Records = sum(Records), by: { Pipeline }
| sort Pipeline desc
